static inline float AT7_ftube(int t, float v){
  float x=(v-AT7_VMIN)*((AT7_N-1)/(AT7_VMAX-AT7_VMIN));
  if(x<=0)x=0; if(x>=AT7_N-1)x=AT7_N-1.001f;
  int i=(int)x; float fr=x-i; const float*T=(t?AT7_FT1:AT7_FT0);
  return T[i]+fr*(T[i+1]-T[i]);
}
